SELECT "APP_GROUP_ID", DATE_TRUNC('day', "SF_CREATED_AT") AS "start_day", COUNT(DISTINCT "USER_ID") AS "unique_users" FROM "USERS_BEHAVIORS_APP_SESSIONSTART_VIEW" WHERE "SF_CREATED_AT" >= '2023-05-25' AND "SF_CREATED_AT" < '2023-06-10' GROUP BY "APP_GROUP_ID", DATE_TRUNC('day', "SF_CREATED_AT") ORDER BY "start_day", "APP_GROUP_ID";
